INSERT INTO pages (slug, title, type) VALUES ('collaboration', 'Collaboration', 'competence');
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'header_title', 'h1', 'Collaboration', 'hero', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'header_breadcrumb', 'label', 'home / compétences', 'hero', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'definition_title', 'h2', 'DEFINITION', 'definition', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'definition_p1', 'paragraph', 'Dans l''IT moderne, l''esprit d''équipe est une compétence majeure.', 'definition', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'definition_p2', 'paragraph', 'La complexité croissante des projets exige une collaboration étroite entre développeurs, administrateurs systèmes et experts métiers que nous pourrions résumer en 4 qualités : la capacité du développeur à exprimer ses idées avec clarté et concision, sa maîtrise du feedback bienveillant lors des code reviews, sa capacité d''écoute active en réunion, l''habitude du partage de connaissances et sa capacité à anticiper les besoins de ses collègues.', 'definition', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section1_number', 'number', '1', 'preuves', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section1_title', 'h2', 'éléments de preuves', 'preuves', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section1_p1', 'paragraph', 'La capacité à collaborer est un soft skill que j''ai toujours développé à travers mes projets durant mes études en programmation. L''esprit d''équipe est mis en avant à chaque étape de la conception et du développement d''un projet logiciel.\n\nPar exemple, lors de la conception d''un projet de location de bungalows en équipe, nous avons réalisé des brainstormings pour définir et affiner les fonctionnalités à concevoir, ainsi que les User Stories (descriptions concises centrées sur l''utilisateur des résultats souhaités) et les tâches dans le backlog.', 'preuves', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section1_p2', 'paragraph', 'L''intelligence collective que favorise l''esprit d''équipe permet de réaliser des projets plus aboutis que si l''on travaillait seul. Lors des hackathons et marathons créatifs auxquels j''ai participé, comme Museomix en Alsace ou le Scientific Game Jam de Strasbourg, des groupes de travail se réunissaient pendant 48 heures, rassemblant des experts variés tels que menuisiers, designers, sound designers, programmeurs, communicants, et experts en contenu.\n\nCette expérience m''a appris à collaborer, car le manque de temps exige une compréhension rapide et une réactivité face aux besoins des autres membres pour avancer vers la réalisation d''un prototype. Ces événements nécessitent également de collaborer avec les coachs, experts en contenu et organisateurs, car certaines connaissances ou compétences peuvent faire défaut et impacter le projet.\n\nJ''ai participé à trois Museomix, un Hacking Health Camp et un Scientific Game Jam, où j''ai pu collaborer en tant que développeur, designer ou sound designer. Ce qui a été le plus intéressant, c''est que l''esprit d''équipe nous pousse à sortir de nos compétences habituelles pour répondre aux besoins techniques du projet. Dans mon rôle de programmeur chez Coliback, la compétence de collaboration au sein d''une équipe d''informaticiens aux expertises variées est essentielle.\n\nPar exemple, pour la conception de l''application MyCityStock, développée par la startup du même nom, j''ai travaillé en binôme avec mon responsable sur la mise en place d''un back-office permettant aux administrateurs d''avoir des droits d''écriture et de révision supérieurs à ceux des utilisateurs de l''application.\n\nDans cette démarche de conception, j''ai rapidement configuré un Directus dans un environnement Docker et participé à la conception des points de contact entre la base de données de l''application et le back-office, en collaboration avec David, mon responsable, au sein d''une équipe comprenant un expert en infogérance et un ingénieur logiciel spécialisé dans le développement d''applications web.\n\nNous échangions fréquemment dans une démarche de conception commune, où chaque réunion nécessitait une écoute active pour expliquer clairement les améliorations techniques, les tâches ou fonctionnalités développées sur notre périmètre métier, et identifier les besoins, enjeux, conséquences éventuelles et améliorations à réaliser par les autres experts sur leur périmètre.\n\nAvec du recul, ce projet a été très enrichissant, car nous avons créé une application tout en apprenant beaucoup des autres. Dans l''activité de codage, j''ai également pratiqué beaucoup de pair programming en équipe pour améliorer la qualité du code produit et résoudre des problèmes complexes.\n\nPar exemple, lors de la conception et du développement de l''application de location de bungalows, nous avons dû réfléchir à la manière de filtrer les bungalows selon les préférences des utilisateurs, en tenant compte de cela tout au long du parcours de vie de l''application. Pour ce faire, nous avons commencé par réaliser des schémas, puis des diagrammes UML basés sur des bus d''événements, avant de rédiger du pseudo-code commun et d''implémenter la solution.\n\nChez Coliback, il arrivait que l''application ColibackPremium rencontre des problèmes techniques ou des régressions de version. Sous pression, nous devions identifier la source de l''erreur, qui pouvait être liée à la requête envoyée par l''utilisateur, à l''environnement technique dans lequel la solution s''intègre, ou à la logique du code source de l''application.\n\nPour développer l''offre ColibackPremium, j''ai travaillé en binôme avec David, qui s''occupait de la partie frontend en développant un portail sur le site de Coliback pour les clients des e-commerçants souhaitant effectuer un retour produit. Nous avons dû collaborer étroitement pour concevoir et identifier les besoins dans le développement du projet à court et long terme.\n\nActuellement, six mois après la mise en ligne de la solution, plus de 6000 produits transitent par la solution que nous avons développée.', 'preuves', 4);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section2_number', 'number', '2', 'evolution', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section2_title', 'h2', 'Autocritique', 'evolution', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section2_p1', 'paragraph', 'Le métier de développeur est de plus en plus axé sur la sociabilité, le travail en équipe sur des projets, l''intégration dans une communauté de savoirs, et l''apport de compétences techniques sur des projets non informatiques.\n\nL''esprit d''équipe rend ce métier passionnant. Cependant, lorsqu''on travaille en équipe, il est essentiel d''adopter des méthodologies et des outils adaptés. Le rôle de chef de projet devient alors crucial pour éviter de ralentir le rythme de production d''un projet en raison d''un manque de compréhension des rôles des autres parties prenantes.', 'evolution', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section3_number', 'number', '3', 'autocritique', 1);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section3_title', 'h2', 'évolution', 'autocritique', 2);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'section3_p1', 'paragraph', 'Allié à la créativité et naturellement sociable, l''idée de collaborer avec d''autres experts en informatique ou d''autres profils différents du mien est épanouissant.\n\nCela m''encourage à continuer à participer à des projets open-source, freelance, design, domotiques etc… par soucis d''apprentissage mais également par soucis de performance des logiciels conçus.', 'autocritique', 3);
INSERT INTO content_blocks (page_slug, block_key, type, value, category, order_index) VALUES ('collaboration', 'projects_title', 'h2', 'projets', 'projets', 1);
